## Step 5: Calculate New APP Mass

```
Refactored Code Mass:

const PROCESSING_FEE = 5;                                              // 1 constant (5)
const BASE_PREMIUMS = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25 };
                                                                        // 1 assignment, 5 constants
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);                 // 1 assignment, 1 invocation, 2 constants
const BLOCK_SIZE = 3;                                                   // 1 constant
const BLOCK_PREMIUM = 60;                                               // 1 constant

const basePremium = (item) => BASE_PREMIUMS[item.type] ?? 0;           // 1 binding, 1 conditional, 1 constant

const isComponent = (item) => COMPONENT_TYPES.has(item.type);          // 1 binding, 1 invocation

const componentBlockPremium = (type, count) =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
                                                                        // 2 bindings, 1 conditional (ternary), 1 conditional (??)

const itemsPremium = (items) => {
  const components: Item[] = [];                                        // 1 binding, 1 assignment, 1 constant ([])
  const nonComponents: Item[] = [];                                     // 1 binding, 1 assignment, 1 constant ([])
  for (const item of items) {                                           // 1 loop, 1 binding
    (isComponent(item) ? components : nonComponents).push(item);        // 1 invocation (isComponent), 1 conditional, 1 invocation (push)
  }

  const counts: Record<string, number> = {};                            // 1 binding, 1 assignment, 1 constant ({})
  for (const item of components) {                                      // 1 loop, 1 binding
    counts[item.type] = (counts[item.type] ?? 0) + 1;                  // 1 assignment, 1 conditional, 1 constant (0), 1 constant (1)
  }

  const mainPremium = nonComponents.reduce((sum, item) => sum + basePremium(item), 0);
                                                                        // 1 binding, 1 invocation (reduce), 2 bindings (sum, item), 1 invocation (basePremium), 1 constant (0)
  const componentTotal = Object.entries(counts).reduce(
    (sum, [type, count]) => sum + componentBlockPremium(type, count), 0);
                                                                        // 1 binding, 1 invocation (Object.entries), 1 invocation (reduce), 2 bindings (sum, [type, count]), 1 invocation (componentBlockPremium), 1 constant (0)
  return mainPremium + componentTotal;
};

export const quote = (customer, items, isFollowUp) => {
  const premium = itemsPremium(items);                                  // 3 bindings, 1 binding (premium), 1 invocation (itemsPremium)
  return premium + PROCESSING_FEE;
};
```

**Component Count:**
- Constants: 1(5) + 5(100,60,80,40,25) + 2("rune","moonstone") + 1(3) + 1(60) + 1(0 basePremium) + 1([]) + 1([]) + 1({}) + 1(0) + 1(1) + 1(0 reduce) + 1(0 reduce2) = 18 x 1 = **18**
- Bindings: 1(item basePremium) + 1(item isComponent) + 2(type, count componentBlockPremium) + 1(items) + 1(components) + 1(nonComponents) + 1(item loop1) + 1(counts) + 1(item loop2) + 1(mainPremium) + 2(sum, item reduce) + 1(componentTotal) + 2(sum, [type,count] reduce2) + 3(customer, items, isFollowUp) + 1(premium) = 20 x 1 = **20**
